    # -------------------------------------------------------------------------
    # Redirect URI Validation (SECURITY CRITICAL)
    # -------------------------------------------------------------------------

    @staticmethod
    def _validate_redirect_uri_format(uri: str) -> Optional[str]:
        """
        Validate that a redirect URI meets security requirements.

        Returns the normalized URI if valid, None otherwise.
        """
        if not isinstance(uri, str) or not uri.strip():
            return None

        uri = uri.strip()

        parsed = urlparse(uri)

        # MUST use HTTPS (except localhost for development)
        is_localhost = parsed.hostname in ("localhost", "127.0.0.1", "::1")
        if not is_localhost and parsed.scheme != "https":
            logger.warning("Rejected redirect URI: non-HTTPS scheme")
            return None

        if is_localhost and parsed.scheme not in ("http", "https"):
            return None

        # Must have a valid hostname
        if not parsed.hostname:
            return None

        # Reject URIs with fragments (RFC 6749 Section 3.1.2)
        if parsed.fragment:
            logger.warning("Rejected redirect URI: contains fragment")
            return None

        # Reject URIs with user info (potential open redirect via @)
        if parsed.username or parsed.password:
            logger.warning("Rejected redirect URI: contains userinfo")
            return None

        # Reject suspicious characters that could enable parsing confusion
        suspicious_chars = ('\x00', '\t', '\n', '\r', '\\', '@', '%00')
        for char in suspicious_chars:
            if char in uri:
                logger.warning("Rejected redirect URI: contains suspicious characters")
                return None

        # Normalize: rebuild without trailing variations
        normalized = urlunparse((
            parsed.scheme,
            parsed.netloc,
            parsed.path or "/",
            parsed.params,
            parsed.query,
            "",  # No fragment
        ))

        return normalized

    def _is_redirect_uri_allowed(self, client_id: str, redirect_uri: str) -> bool:
        """
        SECURITY CRITICAL: Validate redirect_uri using EXACT string matching.

        Per RFC 6749 Section 3.1.2.3:
        "The authorization server MUST compare the two URIs using simple
         string comparison as defined in [RFC3986] Section 6.2.1."

        WARNING: Do NOT use startswith(), endswith(), substring matching,
        or regex patterns. These enable open redirect attacks:
          - startswith("https://legit.com") matches "https://legit.com.evil.com"
          - startswith("https://legit.com") matches "https://legit.com@evil.com"

        Multiple environments are supported by registering each URI explicitly.
        """
