        if not client or not client.is_active:
            return False

        # Normalize the incoming URI the same way we normalized at registration
        normalized_uri = self._validate_redirect_uri_format(redirect_uri)
        if normalized_uri is None:
            return False

        # EXACT MATCH ONLY - this is the secure approach
        # Use constant-time comparison to prevent timing attacks on URI values
