    # -------------------------------------------------------------------------
    # Helper Methods
    # -------------------------------------------------------------------------

    @staticmethod
    def _hash_secret(secret: str) -> str:
        """Hash a client secret for storage using a strong KDF."""
        salt = os.urandom(32)
        key = hashlib.pbkdf2_hmac("sha256", secret.encode("utf-8"), salt, 600_000)
        return salt.hex() + ":" + key.hex()

    @staticmethod
    def _verify_secret(secret: str, stored_hash: str) -> bool:
        """Verify a client secret against stored hash."""
        try:
            salt_hex, key_hex = stored_hash.split(":", 1)
            salt = bytes.fromhex(salt_hex)
            stored_key = bytes.fromhex(key_hex)
            computed_key = hashlib.pbkdf2_hmac(
                "sha256", secret.encode("utf-8"), salt, 600_000
            )
            return hmac.compare_digest(computed_key, stored_key)
        except (ValueError, AttributeError):
            return False

    @staticmethod
    def _verify_pkce(code_verifier: str, code_challenge: str, method: str) -> bool:
        """Verify PKCE code verifier against stored challenge."""
        if method == "S256":
            digest = hashlib.sha256(code_verifier.encode("ascii")).digest()
            computed = (
                digest.hex()  # We'll use base64url in production
            )
            # For proper implementation, use base64url encoding
            import base64
            computed = base64.urlsafe_b64encode(digest).rstrip(b"=").decode("ascii")
            return hmac.compare_digest(computed, code_challenge)
        return False

    def _revoke_tokens_for_code(self, code: str) -> None:
        """Revoke all tokens issued from a specific authorization code."""
        to_revoke = [
            token for token, data in self._tokens.items()
            if data.get("auth_code") == code
        ]
        for token in to_revoke:
            del self._tokens[token]
            logger.info("Revoked token due to authorization code reuse")

    @staticmethod
    def _build_error_redirect(
        redirect_uri: str, error: str, description: str, state: Optional[str]
    ) -> dict:
        """Build an error redirect response."""
        parsed = urlparse(redirect_uri)
        params = parse_qs(parsed.query)
        params["error"] = [error]
        params["error_description"] = [description]
        if state:
            params["state"] = [state]

        redirect_url = urlunparse((
            parsed.scheme, parsed.netloc, parsed.path,
            parsed.params, urlencode(params, doseq=True), "",
        ))
        return {"redirect_to": redirect_url, "error": error}

    def validate_access_token(self, token: str) -> Optional[dict]:
        """Validate an access token and return associated data."""
        token_data = self._tokens.get(token)
        if not token_data:
            return None
        if time.time() > token_data["expires_at"]:
            del self._tokens[token]
            return None
        return {
            "client_id": token_data["client_id"],
            "user_id": token_data["user_id"],
            "scopes": token_data["scopes"],
        }


